#!/usr/bin/env python3
r"""
strings_server.py -- self-contained Strings & Inverter app (collector + web viewer in one file).

Polls a Tesla Powerwall-3 Gateway over its LOCAL TEDAPI interface (no cloud, no Tesla login)
for per-string (MPPT) power/voltage + inverter telemetry, stores it in a small SQLite file
(StringsDB), and serves a web page: per-string energy cards, inverter tiles, and four charts
(string power, string voltage, AC output + cooling fan, grid frequency + voltage). Time-range
pills (3h/6h/1d/7d/30d/6mo/12mo/All), a custom date-range filter, and an Excel export.

Dependencies (pip):  flask, openpyxl, pypowerwall   (see requirements.txt)

RUN -- collect from the gateway AND serve the page (one process):
   python strings_server.py --host 192.168.91.1 --password XXXXX --port 8800 --interval 60

RUN -- just view already-collected data, don't poll the gateway:
   python strings_server.py --no-collect --port 8800

Flags (env vars TEDAPI_HOST / TEDAPI_PASSWORD / STRINGSDB / PORT also work):
   --host       gateway IP (default 192.168.91.1)
   --password   gateway local password (last 5 chars of the serial on recent units)
   --db         StringsDB path (default StringsDB.db next to this file)
   --port       web port (default 8800)
   --interval   seconds between samples (default 60)
   --bind       web bind address (default 0.0.0.0)
   --no-collect serve existing data only, don't poll the gateway
"""
import argparse
import io
import os
import sqlite3
import sys
import threading
import time
from datetime import datetime, timezone

from flask import Flask, jsonify, request, Response, send_file

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
DEFAULT_DB = os.path.expandvars(os.environ.get("STRINGSDB", os.path.join(BASE_DIR, "StringsDB.db")))
DEFAULT_PORT = int(os.environ.get("PORT", "8800"))

app = Flask(__name__)
DB_PATH = DEFAULT_DB

SPANS = {"3h": 3*3600, "6h": 6*3600, "1d": 86400, "7d": 7*86400,
         "30d": 30*86400, "6mo": 182*86400, "12mo": 365*86400}


# ===========================================================================
#  LOCAL TEDAPI CLIENT -- read per-string + inverter detail from the gateway
#  (needs pypowerwall; only used when collecting, i.e. not with --no-collect)
# ===========================================================================
_pw = None
_last_connect = 0.0


def _get_pw(host, password):
    """Lazily create + cache a connected pypowerwall handle, reconnecting periodically."""
    global _pw, _last_connect
    import pypowerwall
    now = time.time()
    if _pw is None or (now - _last_connect) > 600:   # refresh the session every 10 min
        _pw = pypowerwall.Powerwall(host, gw_pwd=password)
        _pw.connect()
        _last_connect = now
    return _pw


def _num(x):
    try:
        return float(x)
    except (TypeError, ValueError):
        return None


def _extract_inverter(vitals):
    """Pull inverter scalars from the PVAC device. On this hardware: Fout=grid Hz,
    Vout=AC output V, Pout=AC output W, Fan_Speed_Actual_RPM=cooling fan. Missing -> None."""
    out = {"inv_temp_c": None, "grid_hz": None, "grid_v": None, "ac_pout": None, "fan_rpm": None}
    for dev, fields in (vitals or {}).items():
        if not isinstance(fields, dict) or dev.split("--")[0] != "PVAC":
            continue
        for k, val in fields.items():
            n = _num(val)
            if out["grid_hz"] is None and k.endswith("Fout") and n and 40 < n < 70:
                out["grid_hz"] = n
            elif out["grid_v"] is None and k.endswith("Vout") and n and 50 < n < 320:
                out["grid_v"] = n
            elif out["ac_pout"] is None and k.endswith("Pout"):
                out["ac_pout"] = n
            elif out["fan_rpm"] is None and "Fan_Speed_Actual" in k:
                out["fan_rpm"] = n
            elif out["inv_temp_c"] is None and k.endswith("Temperature"):
                out["inv_temp_c"] = n
    return out


def poll_detail(host, password):
    """Return per-string + inverter detail:
       {'strings': {name: {power,voltage,current,state}}, inv_temp_c, grid_hz,
        grid_v, ac_pout, fan_rpm}. Any field this gateway does not expose is None."""
    pw = _get_pw(host, password)
    out = {"strings": {}, "inv_temp_c": None, "grid_hz": None,
           "grid_v": None, "ac_pout": None, "fan_rpm": None}
    try:
        for name, d in (pw.strings() or {}).items():
            if isinstance(d, dict):
                out["strings"][str(name)] = {
                    "power": _num(d.get("Power")),
                    "voltage": _num(d.get("Voltage")),
                    "current": _num(d.get("Current")),
                    "state": d.get("State") or d.get("PvState"),
                }
    except Exception:
        pass
    try:
        out.update(_extract_inverter(pw.vitals() or {}))
    except Exception:
        pass
    if out["inv_temp_c"] is None:
        try:
            vals = [_num(v) for v in (pw.temps() or {}).values() if _num(v) is not None]
            if vals:
                out["inv_temp_c"] = vals[0]
        except Exception:
            pass
    return out


# ===========================================================================
#  COLLECTOR -- write samples into the SAME two tables the page reads
# ===========================================================================
DDL = """
CREATE TABLE IF NOT EXISTS live_strings (
    ts INTEGER, name TEXT,
    power REAL, voltage REAL, current REAL, state TEXT,
    PRIMARY KEY (ts, name)
);
CREATE TABLE IF NOT EXISTS live_detail (
    ts INTEGER PRIMARY KEY,
    inv_temp_c REAL, grid_hz REAL, grid_v REAL, ac_pout REAL, fan_rpm REAL
);
"""


def db_connect(path):
    d = os.path.dirname(path)
    if d:
        os.makedirs(d, exist_ok=True)
    c = sqlite3.connect(path, timeout=30)
    c.executescript(DDL)
    c.commit()
    return c


def write_sample(c, d):
    ts = int(datetime.now(timezone.utc).timestamp())
    strings = d.get("strings") or {}
    rows = [(ts, name, s.get("power"), s.get("voltage"), s.get("current"), s.get("state"))
            for name, s in strings.items()]
    if rows:
        c.executemany("INSERT OR REPLACE INTO live_strings(ts,name,power,voltage,current,state) "
                      "VALUES(?,?,?,?,?,?)", rows)
    c.execute("INSERT OR REPLACE INTO live_detail(ts,inv_temp_c,grid_hz,grid_v,ac_pout,fan_rpm) "
              "VALUES(?,?,?,?,?,?)",
              (ts, d.get("inv_temp_c"), d.get("grid_hz"), d.get("grid_v"),
               d.get("ac_pout"), d.get("fan_rpm")))
    c.commit()
    return ts, len(rows)


def collect_loop(host, password, db_path, interval=60, stop=None, quiet=False):
    """Poll the gateway repeatedly into db_path until `stop` (a threading.Event) is set."""
    c = db_connect(db_path)
    interval = max(5, int(interval))
    while stop is None or not stop.is_set():
        try:
            d = poll_detail(host, password)
            ts, n = write_sample(c, d)
            if not quiet:
                print(f"[{datetime.now().strftime('%H:%M:%S')}] wrote ts={ts} "
                      f"({n} strings, AC {d.get('ac_pout')} W, fan {d.get('fan_rpm')} rpm)")
        except Exception as e:
            if not quiet:
                print("  poll error:", e)
        for _ in range(interval):                 # sleep in 1s slices so stop is responsive
            if stop is not None and stop.is_set():
                break
            time.sleep(1)
    c.close()


def conn():
    c = sqlite3.connect(DB_PATH, timeout=30)
    c.row_factory = sqlite3.Row
    return c


def _has(c, table):
    return c.execute("SELECT name FROM sqlite_master WHERE type='table' AND name=?",
                     (table,)).fetchone() is not None


def _bucket_for(span):
    if span <= 3*3600:
        return 30
    if span <= 6*3600:
        return 60
    if span <= 86400:
        return 180
    if span <= 7*86400:
        return 900
    if span <= 30*86400:
        return 3600
    if span <= 182*86400:
        return 21600
    if span <= 365*86400:
        return 43200
    return 86400


def _window(c):
    """Return (lo, hi) unix seconds from ?start=&end= (datetime-local) or ?range=."""
    start = request.args.get("start")
    end = request.args.get("end")
    if start and end:
        try:
            lo = int(datetime.fromisoformat(start).timestamp())
            hi = int(datetime.fromisoformat(end).timestamp())
            if lo > hi:
                lo, hi = hi, lo
            return lo, hi
        except ValueError:
            pass
    rng = request.args.get("range", "1d")
    now = int(time.time())
    if rng == "all":
        lo = None
        if _has(c, "live_strings"):
            row = c.execute("SELECT MIN(ts) m FROM live_strings").fetchone()
            lo = row["m"] if row else None
        return (int(lo) if lo else now - 86400), now
    return now - SPANS.get(rng, 86400), now


def _compute(c, lo, hi):
    span = max(1, hi - lo)
    bucket = _bucket_for(span)
    out = {"span": span, "bucket_s": bucket, "lo": lo*1000, "hi": hi*1000,
           "strings": {}, "detail": [], "per_string": {}, "total_now_w": 0,
           "inverter": {}, "balance": {"flag": False, "msg": ""}}
    if not _has(c, "live_strings"):
        return out

    strings = {}
    for r in c.execute(
        "SELECT (ts/?)*? AS tb, name, AVG(power) p, AVG(voltage) v "
        "FROM live_strings WHERE ts>=? AND ts<=? GROUP BY tb, name ORDER BY tb, name",
            (bucket, bucket, lo, hi)):
        strings.setdefault(r["name"], []).append(
            {"t": int(r["tb"])*1000, "p": round(r["p"] or 0, 1), "v": round(r["v"] or 0, 1)})
    out["strings"] = strings

    energy = {n: sum((p["p"] or 0) for p in pts) * bucket / 3600.0 for n, pts in strings.items()}
    total_wh = sum(energy.values()) or 1.0

    now_vals = {}
    for r in c.execute("SELECT name, power, voltage, MAX(ts) ts FROM live_strings GROUP BY name"):
        now_vals[r["name"]] = {"p": r["power"], "v": r["voltage"]}

    for n in sorted(set(list(strings) + list(now_vals))):
        out["per_string"][n] = {
            "kwh": round(energy.get(n, 0.0) / 1000.0, 2),
            "pct": round(100.0 * energy.get(n, 0.0) / total_wh, 1),
            "now_p": (now_vals.get(n) or {}).get("p"),
            "now_v": (now_vals.get(n) or {}).get("v"),
        }
    out["total_now_w"] = round(sum((d["now_p"] or 0) for d in out["per_string"].values()))

    if _has(c, "live_detail"):
        for r in c.execute(
            "SELECT (ts/?)*? AS tb, AVG(ac_pout) ac, AVG(fan_rpm) fan, AVG(grid_v) gv, AVG(grid_hz) hz "
            "FROM live_detail WHERE ts>=? AND ts<=? GROUP BY tb ORDER BY tb",
                (bucket, bucket, lo, hi)):
            out["detail"].append({"t": int(r["tb"])*1000, "ac": round(r["ac"] or 0, 1),
                                  "fan": round(r["fan"] or 0), "gv": round(r["gv"] or 0, 1),
                                   "hz": round(r["hz"] or 0, 3)})
        ext = c.execute("SELECT MAX(fan_rpm) fanmax, MIN(grid_hz) hzmin, MAX(grid_hz) hzmax, "
                        "MIN(grid_v) gvmin, MAX(grid_v) gvmax FROM live_detail "
                        "WHERE ts>=? AND ts<=?", (lo, hi)).fetchone()
        last = c.execute("SELECT ac_pout, fan_rpm, grid_v, grid_hz, MAX(ts) ts FROM live_detail").fetchone()

        def rr(x, n=1):
            return round(x, n) if x is not None else None
        out["inverter"] = {
            "ac": last["ac_pout"] if last else None,
            "fan": last["fan_rpm"] if last else None,
            "gv": last["grid_v"] if last else None,
            "hz": last["grid_hz"] if last else None,
            "ts": last["ts"] if last else None,
            "fan_max": round(ext["fanmax"]) if ext and ext["fanmax"] is not None else None,
            "hz_min": rr(ext["hzmin"], 2) if ext else None,
            "hz_max": rr(ext["hzmax"], 2) if ext else None,
            "gv_min": rr(ext["gvmin"], 1) if ext else None,
            "gv_max": rr(ext["gvmax"], 1) if ext else None,
        }

    powers = {n: (d["now_p"] or 0) for n, d in out["per_string"].items()}
    if powers:
        peak = max(powers.values())
        if peak > 300:
            dead = sorted([n for n, p in powers.items() if p < 0.15 * peak])
            if dead:
                out["balance"] = {"flag": True, "msg": "String(s) " + ", ".join(dead) +
                                  " near zero while peers are producing - check for a faulted/offline string."}
            else:
                out["balance"] = {"flag": False, "msg": "All strings producing in proportion."}
    return out


@app.route("/data.json")
def data():
    c = conn()
    lo, hi = _window(c)
    d = _compute(c, lo, hi)
    c.close()
    return jsonify(d)


@app.route("/export.xlsx")
def export():
    try:
        from openpyxl import Workbook
    except ImportError:
        return Response("openpyxl not installed. Run: pip install openpyxl", status=500)
    c = conn()
    lo, hi = _window(c)
    d = _compute(c, lo, hi)
    c.close()

    wb = Workbook()
    names = sorted(d["strings"].keys())
    tset = set()
    for n in names:
        for p in d["strings"][n]:
            tset.add(p["t"])
    times = sorted(tset)
    pidx = {n: {p["t"]: p["p"] for p in d["strings"][n]} for n in names}
    vidx = {n: {p["t"]: p["v"] for p in d["strings"][n]} for n in names}

    ws = wb.active
    ws.title = "String power (W)"
    ws.append(["Time"] + ["String " + n for n in names])
    for t in times:
        ws.append([datetime.fromtimestamp(t/1000)] + [pidx[n].get(t) for n in names])

    wv = wb.create_sheet("String voltage (V)")
    wv.append(["Time"] + ["String " + n for n in names])
    for t in times:
        wv.append([datetime.fromtimestamp(t/1000)] + [vidx[n].get(t) for n in names])

    wi = wb.create_sheet("Inverter")
    wi.append(["Time", "AC out (W)", "Fan (rpm)", "Grid V", "Grid Hz"])
    for p in d["detail"]:
        wi.append([datetime.fromtimestamp(p["t"]/1000), p["ac"], p["fan"], p["gv"], p["hz"]])

    wsum = wb.create_sheet("Summary")
    wsum.append(["Window start", datetime.fromtimestamp(lo)])
    wsum.append(["Window end", datetime.fromtimestamp(hi)])
    wsum.append([])
    wsum.append(["String", "kWh", "% of output", "now W", "now V"])
    for n in sorted(d["per_string"]):
        ps = d["per_string"][n]
        wsum.append([n, ps["kwh"], ps["pct"], ps["now_p"], ps["now_v"]])
    wsum.append([])
    inv = d["inverter"]
    wsum.append(["Inverter AC now (W)", inv.get("ac")])
    wsum.append(["Fan now / max (rpm)", inv.get("fan"), inv.get("fan_max")])
    wsum.append(["Grid Hz min / max", inv.get("hz_min"), inv.get("hz_max")])
    wsum.append(["Grid V min / max", inv.get("gv_min"), inv.get("gv_max")])

    for sh in (ws, wv, wi):
        for row in sh.iter_rows(min_row=2, max_col=1):
            for cell in row:
                cell.number_format = "yyyy-mm-dd hh:mm"

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    fn = "strings_" + datetime.now().strftime("%Y%m%d_%H%M") + ".xlsx"
    return send_file(buf, as_attachment=True, download_name=fn,
                     mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")


